bomData.valueScript:
//====================================================================
  // Input the BomId's and quantity of baskets
  //====================================================================

  const bomRawData = JSON.parse(partSelf.pa_HardwareId);
  const frameId = bomRawData.FrameId;
  const basketId = bomRawData.BasketId;
  const basketQty = bomRawData.BasketsQty;

    // Type of the Bom-Element (will be checked in order output)
  let elementType='Hardware';

  // ProductionSite Category (to split the orders for different production sites)
  let elementCategory='';

  // Id of the parent to create the hierarchy
  let parentBomId=part.pa_ParentName;

  // Call the function to process the Bom-Element
  GlobalFunc.process_HardwareBom(this, part, elementType, elementCategory, parentBomId, frameId);
  GlobalFunc.process_HardwareBom(this, part, elementType, elementCategory, parentBomId, basketId, basketQty);
